		@Override
		public List<RuleApplication> apply(MemoExpr expression, OptimizationGoal goal, RuleContext context) {
			int childGroupId = expression.inputGroupIds().getFirst();
			factRevisionBeforeRefinement.compareAndSet(-1L, context.memo().group(childGroupId).factRevision());
			PhysicalProperties refined = PhysicalProperties.builder()
					.accessPath("versioned-finite-scan")
					.bindingProfile(finiteProfile("o", iri("urn:test:object")))
					.build();
			return List.of(RuleApplication.physical(childGroupId, child.clone(), refined, CostVector.ZERO,
					proof(expression, goal, context), "versioned-output-fact"));
		}
