	private static StatementPattern pattern() {
		return new StatementPattern(Var.of("s"), Var.of("p"), Var.of("o"));
	}

	private static CostVector exactCost(double rows) {
		return new CostVector(rows, rows, 0.0d, 0.0d, 0.0d, 1.0d, 1.0d);
	}

	private static BindingProfile finiteProfile(String variable, Value value) {
		FiniteRelationEstimate relation = FiniteRelationEstimate.fromRows(List.of(variable),
				List.of(List.of(value)), "versioned-output-fact-test");
		BagEstimate bag = BagEstimate.exact(1.0d, "versioned-output-fact-test")
				.withFiniteRelation(relation);
		return BindingProfile.fromBag(null, bag, Map.of());
	}

	private static Value iri(String value) {
		return SimpleValueFactory.getInstance().createIRI(value);
	}

	private static List<MemoChange> drainChanges(Memo memo) {
		ArrayList<MemoChange> changes = new ArrayList<>();
		while (memo.hasPendingChanges()) {
			changes.add(memo.pollChange().orElseThrow());
		}
		return List.copyOf(changes);
	}
